<script setup lang="ts">
import { ref, watch } from 'vue';import{ElDrawer}from'element-plus';import{listCheckins}from'../../services/management/records';import type{CheckinRecord,VisitRecord}from'../../types/records'
const props=defineProps<{modelValue:boolean;visit:VisitRecord|null}>();defineEmits<{'update:modelValue':[boolean];trace:[{type:string;id:string}]}>();const events=ref<CheckinRecord[]>([]),loading=ref(false),error=ref('');const time=(v:string|null)=>v?new Intl.DateTimeFormat('zh-CN',{timeStyle:'medium'}).format(new Date(v)):'暂无'
async function load(){if(!props.visit)return;loading.value=true;error.value='';try{events.value=(await listCheckins({visitId:props.visit.id,pageSize:100})).data.items.sort((a,b)=>a.received_at.localeCompare(b.received_at))}catch(e){error.value=e instanceof Error?e.message:'轨迹加载失败'}finally{loading.value=false}}watch([()=>props.modelValue,()=>props.visit?.id],([visible])=>{if(visible)void load()})
</script>
<template><ElDrawer :model-value="modelValue" title="游览轨迹" size="min(680px,94vw)" @close="$emit('update:modelValue',false)"><template v-if="visit"><h2>{{visit.local_date}} 游览</h2><p>用户 {{visit.user_id}} · 开始 {{time(visit.started_at)}}</p><button @click="$emit('trace',{type:'user',id:visit.user_id})">按用户追踪</button><p v-if="loading">正在加载事件…</p><p v-if="error" class="error">{{error}}</p><ol><li v-for="event in events" :key="event.id"><strong>{{time(event.received_at)}}</strong><span>{{event.checkin_type.toUpperCase()}} · {{event.status==='accepted'?'✓ 已接受':event.status==='duplicate'?'↺ 重复事件':'! '+(event.failure_code||'已拒绝')}}</span><div><button @click="$emit('trace',{type:'spot',id:event.spot_id})">点位</button><button @click="$emit('trace',{type:'device',id:event.device_id})">设备</button><button v-if="event.card_id" @click="$emit('trace',{type:'card',id:event.card_id})">卡片</button></div></li></ol></template></ElDrawer></template>
<style scoped>h2{margin-bottom:4px}p{color:var(--tw-color-muted)}button{min-height:34px;padding:0 9px;border:1px solid var(--tw-color-border);border-radius:7px;background:#fff;color:var(--tw-color-primary)}ol{display:grid;gap:9px;padding:0;list-style:none}li{display:grid;grid-template-columns:80px 1fr auto;align-items:center;gap:10px;padding:11px;border-left:3px solid var(--tw-color-primary);background:#f7f9f7;font-size:11px}li div{display:flex;gap:4px}.error{color:var(--tw-color-danger)}@media(max-width:600px){li{grid-template-columns:1fr}li div{flex-wrap:wrap}}</style>
